-- Production members: 105 real members from Excel + super admin (Shivam).
-- Excludes mock seed. Import AFTER schema.sql + migrations 002-005.
-- Usage: mysql -ulions -p lionsclub < db/members-production.sql
SET FOREIGN_KEY_CHECKS = 0;
SET @club_id = (SELECT id FROM clubs ORDER BY id LIMIT 1);
SET @member_role = (SELECT id FROM roles WHERE code = 'MEMBER');

ON DUPLICATE KEY UPDATE
  name=VALUES(name), initials=VALUES(initials),
  profession=COALESCE(VALUES(profession), profession), area=COALESCE(VALUES(area), area),
  phone=COALESCE(VALUES(phone), phone), joined_year=COALESCE(VALUES(joined_year), joined_year),
  dob=COALESCE(VALUES(dob), dob), spouse=COALESCE(VALUES(spouse), spouse),
  bio=COALESCE(VALUES(bio), bio), active=VALUES(active);

SET FOREIGN_KEY_CHECKS = 1;
